import base64
import anthropic

client = anthropic.Anthropic()

def analyze_image(image_bytes: bytes, mime_type: str, question: str) -> str:
    encoded = base64.standard_b64encode(image_bytes).decode()
    response = client.messages.create(
        model="claude-sonnet-5",
        max_tokens=1024,
        messages=[
            {
                "role": "user",
                "content": [
                    {
                        "type": "image",
                        "source": {
                            "type": "base64",
                            "media_type": mime_type,
                            "data": encoded,
                        },
                    },
                    {"type": "text", "text": question},
                ],
            }
        ],
    )
    return response.content[0].text

# Example: describe an uploaded screenshot
result = analyze_image(
    image_bytes=open("screenshot.png", "rb").read(),
    mime_type="image/png",
    question="Describe the layout of this UI screenshot.",
)

import base64, anthropic

client = anthropic.Anthropic()

def analyze_pdf(pdf_bytes: bytes, question: str) -> str:
    encoded = base64.standard_b64encode(pdf_bytes).decode()
    response = client.messages.create(
        model="claude-sonnet-5",
        max_tokens=2048,
        messages=[
            {
                "role": "user",
                "content": [
                    {
                        "type": "document",
                        "source": {
                            "type": "base64",
                            "media_type": "application/pdf",
                            "data": encoded,
                        },
                    },
                    {"type": "text", "text": question},
                ],
            }
