# For text files (CSV, Markdown, code), read and send as plain text
def analyze_text_file(file_bytes: bytes, filename: str, question: str) -> str:
    text = file_bytes.decode("utf-8", errors="replace")
    prompt = f"File: {filename}\n\n{text}\n\n{question}"
    response = client.messages.create(
        model="claude-sonnet-5",
        max_tokens=2048,
        messages=[{"role": "user", "content": prompt}],
    )
    return response.content[0].text

import base64, anthropic

client = anthropic.Anthropic()

def build_multifile_message(
    text: str,
    attachments: list[tuple[bytes, str, str]],  # (bytes, mime_type, filename)
) -> dict:
    content = []
    for file_bytes, mime, filename in attachments:
        encoded = base64.standard_b64encode(file_bytes).decode()
        if mime.startswith("image/"):
            content.append({
                "type": "image",
                "source": {"type": "base64", "media_type": mime, "data": encoded},
            })
        elif mime == "application/pdf":
            content.append({
                "type": "document",
                "source": {"type": "base64", "media_type": mime, "data": encoded},
            })
            content.append({"type": "text", "text": f"[Document: {filename}]"})
        else:
            # Plain text / CSV / code — inline as text
            file_text = file_bytes.decode("utf-8", errors="replace")
            content.append({"type": "text", "text": f"### {filename}\n\n{file_text}"})
    content.append({"type": "text", "text": text})
    return {"role": "user", "content": content}

# Example: analyse a PDF report and a screenshot together
msg = build_multifile_message(
    text="Summarise the report and identify the issue shown in the screenshot.",
    attachments=[
        (open("report.pdf","rb").read(), "application/pdf", "report.pdf"),
        (open("screenshot.png","rb").read(), "image/png", "screenshot.png"),
    ],
)
response = client.messages.create(
    model="claude-sonnet-5",
    max_tokens=2048,
    messages=[msg],
)
print(response.content[0].text)

import pypdf, io

def check_pdf_pages(pdf_bytes: bytes, max_pages: int = 100) -> int:
    reader = pypdf.PdfReader(io.BytesIO(pdf_bytes))
    count = len(reader.pages)
    if count > max_pages:
        raise ValueError(
            f"PDF has {count} pages, exceeding the {max_pages}-page limit. "
            "Please split the document or provide a specific page range."
        )
    return count

def extract_pdf_page_range(pdf_bytes: bytes, start: int, end: int) -> bytes:
    reader = pypdf.PdfReader(io.BytesIO(pdf_bytes))
    writer = pypdf.PdfWriter()
    for page_num in range(start - 1, min(end, len(reader.pages))):
        writer.add_page(reader.pages[page_num])
    out = io.BytesIO()
    writer.write(out)
    return out.getvalue()
